### 2. No Authentication or Authorization (OWASP A01 – Broken Access Control)

Both `/health` and `/users` are completely open. The `/users` endpoint exposes names and email addresses with zero access control.

**Fix — add JWT middleware:**
```javascript
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>

  if (!token) return res.status(401).json({ error: 'Missing token' });

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Invalid token' });
